import java.io.*;import java.util.*;class Main{static boolean lessPath(ArrayList<Integer> a,ArrayList<Integer> b){if(b==null)return true;for(int i=0;i<a.size()&&i<b.size();i++)if(!a.get(i).equals(b.get(i)))return a.get(i)<b.get(i);return a.size()<b.size();}static ArrayList<Integer> solve(int[] coins,int maxJump){int n=coins.length,INF=Integer.MAX_VALUE/4;int[] dp=new int[n];Arrays.fill(dp,INF);@SuppressWarnings("unchecked") ArrayList<Integer>[] path=new ArrayList[n];if(coins[n-1]==-1)return new ArrayList<>();dp[n-1]=coins[n-1];path[n-1]=new ArrayList<>(List.of(n));for(int i=n-2;i>=0;i--){if(coins[i]==-1)continue;int best=INF;ArrayList<Integer> bestPath=null;for(int j=i+1;j<n&&j<=i+maxJump;j++){if(dp[j]>=INF||path[j]==null)continue;int cost=coins[i]+dp[j];ArrayList<Integer> cand=new ArrayList<>();cand.add(i+1);cand.addAll(path[j]);if(cost<best||cost==best&&lessPath(cand,bestPath)){best=cost;bestPath=cand;}}dp[i]=best;path[i]=bestPath;}return path[0]==null?new ArrayList<>():path[0];}static String fmt(ArrayList<Integer> path){StringBuilder sb=new StringBuilder("[");for(int i=0;i<path.size();i++){if(i>0)sb.append(",");sb.append(path.get(i));}return sb.append("]").toString();}public static void main(String[] a)throws Exception{String text=new String(System.in.readAllBytes()).trim();if(text.isEmpty())return;String[] d=text.split("\\s+");int idx=0,t=Integer.parseInt(d[idx++]);StringBuilder out=new StringBuilder();for(int tc=0;tc<t;tc++){int n=Integer.parseInt(d[idx++]),maxJump=Integer.parseInt(d[idx++]);int[] coins=new int[n];for(int i=0;i<n;i++)coins[i]=Integer.parseInt(d[idx++]);if(tc>0)out.append("\n\n");out.append(fmt(solve(coins,maxJump)));}System.out.print(out);}}
